interface IconBtnProps {
  icon: React.ElementType;
  label: string;
  onClick?: () => void;
  variant?: "ghost" | "outline" | "accent";
  danger?: boolean;
  size?: "sm" | "md";
}

export function IconBtn({ icon: Icon, label, onClick, variant = "ghost", danger = false, size = "md" }: IconBtnProps) {
  const pad = size === "sm" ? "h-7 w-7" : "h-8 w-8";
  const styles: Record<string, string> = {
    ghost:   "text-stone-500 dark:text-stone-400 hover:bg-stone-100 dark:hover:bg-[#2A2A2A] hover:text-stone-800 dark:hover:text-stone-200",
    outline: "border border-[#E8E6E1] dark:border-[#333] text-stone-600 dark:text-stone-400 hover:bg-stone-50 dark:hover:bg-[#2A2A2A] hover:border-stone-300 dark:hover:border-[#555]",
    accent:  "bg-blue-600 text-white hover:bg-blue-700 shadow-sm",
  };
  const dangerStyle = danger ? "text-stone-500 dark:text-stone-400 hover:bg-red-50 dark:hover:bg-red-950/50 hover:text-red-600 dark:hover:text-red-400" : "";
  return (
    <button onClick={onClick} aria-label={label} title={label}
      className={`inline-flex items-center justify-center rounded-lg transition-all duration-150 font-medium ${pad} ${danger ? dangerStyle : styles[variant]}`}>
      <Icon size={15} strokeWidth={1.8} />
    </button>
  );
}

interface LabeledBtnProps {
  icon: React.ElementType;
  label: string;
  onClick?: () => void;
  accent?: boolean;
  danger?: boolean;
  disabled?: boolean;
}

export function LabeledBtn({ icon: Icon, label, onClick, accent = false, danger = false, disabled = false }: LabeledBtnProps) {
  let cls = "inline-flex items-center gap-2 px-3 h-8 rounded-lg text-xs font-medium transition-all duration-150 border ";
  if (disabled) {
    cls += "text-stone-300 dark:text-stone-600 border-[#E8E6E1]/50 dark:border-[#333]/50 cursor-not-allowed bg-stone-50 dark:bg-[#1A1A1A]";
  } else if (accent) cls += "bg-blue-600 text-white border-transparent hover:bg-blue-700 shadow-sm";
  else if (danger) cls += "text-stone-500 dark:text-stone-400 border-[#E8E6E1] dark:border-[#333] hover:bg-red-50 dark:hover:bg-red-950/50 hover:text-red-600 dark:hover:text-red-400 hover:border-red-200 dark:hover:border-red-800";
  else cls += "text-stone-600 dark:text-stone-400 border-[#E8E6E1] dark:border-[#333] hover:bg-stone-50 dark:hover:bg-[#2A2A2A] hover:border-stone-300 dark:hover:border-[#555]";
  return (
    <button onClick={disabled ? undefined : onClick} disabled={disabled} className={cls}>
      <Icon size={13} strokeWidth={1.8} /> {label}
    </button>
  );
}

import { useQuery } from "@tanstack/react-query";
import type { PlanState, WorkerInfo, WorkspaceSummary } from "../types";

const API_BASE = "";

async function fetchPlanState(): Promise<PlanState | null> {
	try {
		const response = await fetch(`${API_BASE}/api/plan-state`);
		if (!response.ok) return null;
		const data = await response.json();

		// Transform to PlanState — the server may return either:
		// Legacy: { title, status, queue: {...}, workers: [...] }
		// New:    { phase, title, status, workspaces: [...] }
		const state: PlanState = {
			phase: data.phase ?? "",
			title: data.title ?? "Plan",
			status: data.status ?? "unknown",
			startedAt: data.startedAt,
			completedAt: data.completedAt,
			workspaces: data.workspaces ?? [],
		};

		return state;
	} catch (error) {
		console.error("Failed to fetch plan state:", error);
		return null;
	}
}

function deriveWorkers(state: PlanState | null | undefined): WorkerInfo[] {
	if (!state?.workspaces) return [];
	return state.workspaces.map((ws) => ({
		id: ws.workspaceId,
		stage: (ws.stage as WorkerInfo["stage"]) ?? "pending",
		attempt: ws.attempts ?? 1,
		retries: 0,
		error: ws.error ?? null,
	}));
}

function deriveQueue(state: PlanState | null | undefined): {
	pending: number;
	active: number;
	blocked: number;
	complete: number;
	failed: number;
} {
	if (!state?.workspaces) return { pending: 0, active: 0, blocked: 0, complete: 0, failed: 0 };
	const byStage: Record<string, number> = {};
	for (const ws of state.workspaces) {
		const s = ws.stage ?? "pending";
		byStage[s] = (byStage[s] ?? 0) + 1;
	}
	return {
		pending: byStage["pending"] ?? 0,
		active: byStage["active"] ?? 0,
		blocked: byStage["blocked"] ?? 0,
		complete: byStage["complete"] ?? 0,
		failed: byStage["failed"] ?? 0,
	};
}

export function usePlanState(enabled: boolean = true) {
	const query = useQuery<PlanState | null>({
		queryKey: ["plan-state"],
		queryFn: fetchPlanState,
		enabled,
		refetchInterval: 5000,
		refetchIntervalInBackground: false,
		staleTime: 2000,
	});

	return {
		data: query.data,
		isLoading: query.isLoading,
		workers: deriveWorkers(query.data),
		queue: deriveQueue(query.data),
	};
}

/** Re-export the derived types for convenience */
export type { PlanState };

import { useCallback, useEffect, useRef, useState } from "react";
import type { ExecutionEvent } from "../types";

const API_BASE = "";
const MAX_EVENTS = 50;

export function useJournalStream(enabled: boolean = true) {
	const [events, setEvents] = useState<ExecutionEvent[]>([]);
	const sourceRef = useRef<EventSource | null>(null);

	const connect = useCallback(() => {
		if (sourceRef.current) {
			sourceRef.current.close();
		}

		const source = new EventSource(`${API_BASE}/api/events`);
		sourceRef.current = source;

		source.onmessage = (event) => {
			try {
				const executionEvent: ExecutionEvent = JSON.parse(event.data);
				setEvents((prev) => {
					const next = [executionEvent, ...prev];
					if (next.length > MAX_EVENTS) next.pop();
					return next;
				});
			} catch (error) {
				console.error("Failed to parse event:", error);
			}
		};

		source.onerror = () => {
			console.error("Event stream error, reconnecting...");
			source.close();
			sourceRef.current = null;
			setTimeout(connect, 5000);
		};
	}, []);

	useEffect(() => {
		if (enabled) {
			connect();
		} else {
			setEvents([]);
		}
		return () => {
			if (sourceRef.current) {
				sourceRef.current.close();
				sourceRef.current = null;
			}
		};
	}, [connect, enabled]);

	return { events };
}
